"""Page discovery module - finds all accessible gateway pages"""

import json
import logging
import os
import re
from datetime import datetime
from urllib.parse import urljoin, urlparse

from bs4 import BeautifulSoup

log = logging.getLogger(__name__)

DEFAULT_CACHE_FILE = "/var/lib/att_gateway/pages.json"


class PageDiscovery:
    """Discovers all accessible configuration pages on the gateway."""

    def __init__(self, gateway_client, cache_file=None):
        """Initialize page discovery.

        Args:
            gateway_client: Authenticated ATTGateway instance
            cache_file: Path to cache file (optional)
        """
        self.gateway = gateway_client
        self.cache_file = cache_file or DEFAULT_CACHE_FILE
        self.discovered_pages = []
        self.visited_urls = set()

    def discover(self, force=False):
        """Run page discovery.

        Args:
            force: If True, ignore cache and re-discover

        Returns:
            List of discovered page dictionaries
        """
        # Load from cache if available and not forcing
        if not force:
            cached = self.load_from_cache()
            if cached:
                log.info(f"Loaded {len(cached)} pages from cache")
                self.discovered_pages = cached
                return cached

        log.info("Starting page discovery...")

        # Common page patterns to try
        common_pages = [
            '/cgi-bin/home.ha',
            '/cgi-bin/sysinfo.ha',
            '/cgi-bin/status.ha',
            '/cgi-bin/devices.ha',
            '/cgi-bin/dhcpserver.ha',
            '/cgi-bin/ipalloc.ha',
            '/cgi-bin/wifi.ha',
            '/cgi-bin/wifi_guest.ha',
            '/cgi-bin/firewall.ha',
            '/cgi-bin/portforwarding.ha',
            '/cgi-bin/routing.ha',
            '/cgi-bin/dns.ha',
            '/cgi-bin/logs.ha',
            '/cgi-bin/reboot.ha',
            '/cgi-bin/backup.ha',
            '/cgi-bin/restore.ha',
            '/cgi-bin/admin.ha',
            '/cgi-bin/password.ha',
        ]

        # Try common pages
        for page_path in common_pages:
            self._try_page(page_path)

        # Try to follow links from discovered pages
        self._follow_links()

        log.info(f"Discovery complete: found {len(self.discovered_pages)} pages")

        # Save to cache
        self.save_to_cache()

        return self.discovered_pages

    def _try_page(self, page_path):
        """Try to access a page and add to discovered list if accessible.

        Args:
            page_path: Path to try (e.g., '/cgi-bin/home.ha')

        Returns:
            True if page is accessible, False otherwise
        """
        # Skip if already visited
        if page_path in self.visited_urls:
            return False

        self.visited_urls.add(page_path)

        try:
            log.debug(f"Trying {page_path}...")
            response = self.gateway.get_page(page_path)

            if response.status_code == 200:
                # Check if it's an actual page (not error/redirect)
                if "Access Code Required" in response.text:
                    log.debug(f"  {page_path} requires authentication")
                    return False

                # Parse page info
                soup = BeautifulSoup(response.text, 'html.parser')

                # Extract title
                title_tag = soup.find('title')
                title = title_tag.text.strip() if title_tag else "Unknown"

                # Check for forms
                forms = soup.find_all('form')
                has_forms = len(forms) > 0

                # Check for input fields
                inputs = soup.find_all('input')
                has_inputs = len(inputs) > 0

                page_info = {
                    'path': page_path,
                    'title': title,
                    'accessible': True,
                    'status_code': response.status_code,
                    'has_forms': has_forms,
                    'form_count': len(forms),
                    'has_inputs': has_inputs,
                    'input_count': len(inputs),
                    'content_length': len(response.text),
                }

                self.discovered_pages.append(page_info)
                log.info(f"  ✓ {page_path} - {title} ({len(forms)} form(s))")
                return True

            else:
                log.debug(f"  {page_path} returned status {response.status_code}")
                return False

        except Exception as e:
            log.debug(f"  {page_path} failed: {e}")
            return False

    def _follow_links(self):
        """Follow links from discovered pages to find more pages."""
        log.info("Following links from discovered pages...")

        # Get all discovered pages so far
        pages_to_check = list(self.discovered_pages)

        for page_info in pages_to_check:
            try:
                # Re-fetch the page to get links
                response = self.gateway.get_page(page_info['path'])
                soup = BeautifulSoup(response.text, 'html.parser')

                # Find all links
                links = soup.find_all('a', href=True)

                for link in links:
                    href = link['href']

                    # Skip external links, anchors, javascript
                    if (href.startswith('http://') or
                        href.startswith('https://') or
                        href.startswith('#') or
                        href.startswith('javascript:')):
                        continue

                    # Make absolute path
                    if not href.startswith('/'):
                        # Relative URL - resolve it
                        base_path = page_info['path'].rsplit('/', 1)[0]
                        href = f"{base_path}/{href}"

                    # Normalize path
                    href = href.split('?')[0]  # Remove query string
                    href = href.split('#')[0]  # Remove anchor

                    # Only interested in .ha, .htm, .html, .cgi pages
                    if any(href.endswith(ext) for ext in ['.ha', '.htm', '.html', '.cgi']):
                        self._try_page(href)

            except Exception as e:
                log.debug(f"Error following links from {page_info['path']}: {e}")

    def load_from_cache(self):
        """Load discovered pages from cache file.

        Returns:
            List of page dictionaries, or None if cache doesn't exist/invalid
        """
        if not os.path.exists(self.cache_file):
            return None

        try:
            with open(self.cache_file, 'r') as f:
                data = json.load(f)

            # Check if cache is recent (less than 7 days old)
            discovered_at = data.get('discovered_at')
            if discovered_at:
                from datetime import datetime, timedelta
                cache_time = datetime.fromisoformat(discovered_at)
                age = datetime.now() - cache_time

                if age > timedelta(days=7):
                    log.info("Cache is older than 7 days, will re-discover")
                    return None

            return data.get('pages', [])

        except Exception as e:
            log.warning(f"Failed to load cache: {e}")
            return None

    def save_to_cache(self):
        """Save discovered pages to cache file."""
        try:
            # Ensure directory exists
            os.makedirs(os.path.dirname(self.cache_file), exist_ok=True)

            cache_data = {
                'discovered_at': datetime.now().isoformat(),
                'firmware_version': self.gateway.firmware_version,
                'page_count': len(self.discovered_pages),
                'pages': self.discovered_pages,
            }

            with open(self.cache_file, 'w') as f:
                json.dump(cache_data, f, indent=2)

            log.info(f"Saved {len(self.discovered_pages)} pages to cache")

        except Exception as e:
            log.warning(f"Failed to save cache: {e}")

    def get_pages_by_category(self):
        """Categorize discovered pages by function.

        Returns:
            Dictionary mapping categories to page lists
        """
        categories = {
            'system': [],
            'network': [],
            'wifi': [],
            'security': [],
            'advanced': [],
            'logs': [],
            'admin': [],
            'other': [],
        }

        for page in self.discovered_pages:
            path_lower = page['path'].lower()
            title_lower = page['title'].lower()

            if any(x in path_lower or x in title_lower for x in ['sysinfo', 'status', 'home', 'device']):
                categories['system'].append(page)
            elif any(x in path_lower or x in title_lower for x in ['dhcp', 'ipalloc', 'routing', 'dns']):
                categories['network'].append(page)
            elif 'wifi' in path_lower or 'wireless' in title_lower:
                categories['wifi'].append(page)
            elif any(x in path_lower or x in title_lower for x in ['firewall', 'forward', 'port']):
                categories['security'].append(page)
            elif any(x in path_lower or x in title_lower for x in ['log', 'event']):
                categories['logs'].append(page)
            elif any(x in path_lower or x in title_lower for x in ['admin', 'password', 'reboot', 'backup', 'restore']):
                categories['admin'].append(page)
            else:
                categories['other'].append(page)

        return categories

    def print_summary(self):
        """Print a summary of discovered pages."""
        print("\n" + "=" * 60)
        print("PAGE DISCOVERY SUMMARY")
        print("=" * 60)
        print(f"Total pages discovered: {len(self.discovered_pages)}")
        print()

        categories = self.get_pages_by_category()

        for category, pages in categories.items():
            if pages:
                print(f"{category.upper()} ({len(pages)} pages):")
                for page in pages:
                    forms_str = f" [{page['form_count']} form(s)]" if page['has_forms'] else ""
                    print(f"  {page['path']:40s} {page['title']}{forms_str}")
                print()

        print("=" * 60)
